import sys
from typing import Optional

class ListNode:
    def __init__(self, val: int = 0, next: Optional['ListNode'] = None):
        self.val = val
        self.next = next

class Solution:
    def removeNthFromEnd(self, head: Optional[ListNode], n: int) -> Optional[ListNode]:
        dummy = ListNode(0, head)
        first = dummy
        second = dummy
        # advance first n+1 steps
        for _ in range(n + 1):
            if first:
                first = first.next
        # move both until first reaches end
        while first:
            first = first.next
            second = second.next
        # remove node
        if second.next:
            second.next = second.next.next
        return dummy.next

def build_linked_list(values):
    dummy = ListNode(0)
    cur = dummy
    for v in values:
        cur.next = ListNode(v)
        cur = cur.next
    return dummy.next

def linked_list_to_list(head):
    res = []
    while head:
        res.append(head.val)
        head = head.next
    return res

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    try:
        length = int(next(it))
        vals = [int(next(it)) for _ in range(length)]
        n = int(next(it))
    except StopIteration:
        sys.exit(0)
    head = build_linked_list(vals)
    sol = Solution()
    new_head = sol.removeNthFromEnd(head, n)
    out = linked_list_to_list(new_head)
    print(' '.join(map(str, out)))

